"use client";

import * as React from "react";
import {
  IconBuildingStore,
  IconReceiptYen,
  IconUsers,
  IconUsersGroup,
  IconCoin,
  IconRefresh,
  IconChartBar,
  IconDownload,
  IconInfoCircle,
} from "@tabler/icons-react";
import {
  Container,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  StatGroup,
  AnalyticsCard,
  LineChart,
  StackedBarChart,
  ParetoChart,
  LabeledDonutCard,
  HeatmapChart,
  DataTable,
  Badge,
  Meter,
  Separator,
  Select,
  ToggleGroup,
  ToggleGroupItem,
  Button,
  ChartLegend,
  type ColumnDef,
  type ChartColor,
  formatCurrency,
  formatNumber,
  formatPercent,
} from "@gunjo/ui";
import {
  PERIODS,
  STORES,
  KPI_BY_PERIOD,
  DAILY_SALES,
  DAILY_BUDGET_LINE,
  DAYPART_SALES,
  MENU_RANKING,
  CATEGORY_SHARE,
  HEATMAP_DAYS,
  HEATMAP_BANDS,
  HEATMAP_CELLS,
  PER_GUEST_TREND,
  type PeriodKey,
  type MenuRankItem,
} from "./data";

/* ------------------------------------------------------------------ */
/* formatters (kept inside the client boundary — function-prop SSR rule) */
/* ------------------------------------------------------------------ */
const yen = (v: number) => formatCurrency(v, { maximumFractionDigits: 0 });
const yenCompact = (v: number) => formatCurrency(v, { compact: true, maximumFractionDigits: 1 });
const sen = (v: number) => `${formatNumber(v)}千`; // ヒートマップ: 千円

const categoryColor: Record<MenuRankItem["category"], ChartColor> = {
  コース: "primary",
  フード: "info",
  ドリンク: "accent",
  デザート: "warning",
};

const categoryBadge: Record<MenuRankItem["category"], "default" | "secondary" | "outline" | "warning"> = {
  コース: "default",
  フード: "secondary",
  ドリンク: "outline",
  デザート: "warning",
};

/* ------------------------------------------------------------------ */

export default function RestaurantSalesPage() {
  const [period, setPeriod] = React.useState<PeriodKey>("month");
  const [storeId, setStoreId] = React.useState<string>(STORES[0].id);

  const kpi = KPI_BY_PERIOD[period];
  const periodMeta = PERIODS.find((p) => p.key === period)!;
  const storeName = STORES.find((s) => s.id === storeId)!.name;

  // 派生指標
  const yoy = (kpi.netSales / kpi.lastYearSales - 1) * 100; // 前年同月比 %
  const budgetRate = (kpi.netSales / kpi.budget) * 100; // 予算達成率 %
  const foodDrinkRatio = kpi.foodSales / (kpi.foodSales + kpi.drinkSales);

  /* KPI ストリップ -------------------------------------------------- */
  const stats = [
    {
      label: "客数",
      value: `${formatNumber(kpi.guests)}人`,
      change: `${formatNumber(kpi.groups)}組`,
      trend: "flat" as const,
      hint: "組数",
    },
    {
      label: "客単価",
      value: yen(kpi.perGuest),
      change: `フード比 ${formatPercent(foodDrinkRatio, { asPercentValue: false, maximumFractionDigits: 0 })}`,
      trend: "up" as const,
      hint: "／ドリンク",
    },
    {
      label: "回転率",
      value: `${kpi.turnover.toFixed(1)}回転`,
      change: "席あたり",
      trend: "flat" as const,
    },
    {
      label: "原価率",
      value: formatPercent(kpi.costRatio, { asPercentValue: false }),
      change: kpi.costRatio <= 0.3 ? "目標内 (≤30%)" : "目標超過",
      trend: kpi.costRatio <= 0.3 ? ("up" as const) : ("down" as const),
      tone: kpi.costRatio <= 0.3 ? ("positive" as const) : ("negative" as const),
    },
  ];

  /* 日次売上推移 ---------------------------------------------------- */
  const lineSeries = [
    {
      label: "今年",
      color: "primary" as ChartColor,
      data: DAILY_SALES.map((d) => ({ label: `${d.day}日`, value: d.sales })),
    },
    {
      label: "前年",
      color: "muted" as ChartColor,
      data: DAILY_SALES.map((d) => ({ label: `${d.day}日`, value: d.lastYear })),
    },
  ];

  /* 時間帯別（フード/ドリンク 積み上げ） ----------------------------- */
  const daypartGroups = DAYPART_SALES.map((d) => ({
    label: d.daypart,
    segments: [
      { label: "フード", value: d.food, color: "info" as ChartColor },
      { label: "ドリンク", value: d.drink, color: "accent" as ChartColor },
    ],
  }));

  /* ABC / パレート -------------------------------------------------- */
  const paretoData = MENU_RANKING.map((m) => ({
    label: m.name,
    value: m.sales,
    color: categoryColor[m.category],
  }));

  // ABC ランク（累積構成比 70% / 90% で A/B/C 区分）
  const totalSales = MENU_RANKING.reduce((s, m) => s + m.sales, 0);
  let cum = 0;
  const ranked = MENU_RANKING.map((m) => {
    cum += m.sales;
    const cumPct = (cum / totalSales) * 100;
    const grade: "A" | "B" | "C" = cumPct <= 70 ? "A" : cumPct <= 90 ? "B" : "C";
    return { ...m, cumPct, grade };
  });

  const columns: ColumnDef<(typeof ranked)[number]>[] = [
    {
      accessorKey: "rank",
      header: "順位",
      cell: ({ row }) => <span className="tabular-nums text-muted-foreground">{row.original.rank}</span>,
      size: 56,
    },
    {
      accessorKey: "name",
      header: "メニュー",
      cell: ({ row }) => (
        <div className="flex min-w-0 flex-col gap-1">
          <span className="truncate font-medium">{row.original.name}</span>
          <Badge variant={categoryBadge[row.original.category]} className="w-fit">
            {row.original.category}
          </Badge>
        </div>
      ),
    },
    {
      accessorKey: "qty",
      header: "数量",
      cell: ({ row }) => <span className="tabular-nums">{formatNumber(row.original.qty)}</span>,
      size: 72,
    },
    {
      accessorKey: "sales",
      header: "売上",
      cell: ({ row }) => <span className="tabular-nums font-medium">{yen(row.original.sales)}</span>,
      size: 116,
    },
    {
      accessorKey: "cumPct",
      header: "累積構成比",
      cell: ({ row }) => (
        <span className="tabular-nums text-muted-foreground">
          {formatPercent(row.original.cumPct, { asPercentValue: true, maximumFractionDigits: 1 })}
        </span>
      ),
      size: 104,
    },
    {
      accessorKey: "costRatio",
      header: "原価率",
      cell: ({ row }) => {
        const over = row.original.costRatio > 0.35;
        return (
          <span className={`tabular-nums ${over ? "text-destructive" : ""}`}>
            {formatPercent(row.original.costRatio, { asPercentValue: false })}
          </span>
        );
      },
      size: 84,
    },
    {
      accessorKey: "grade",
      header: "ABC",
      cell: ({ row }) => {
        const g = row.original.grade;
        const v = g === "A" ? "success" : g === "B" ? "warning" : "outline";
        return <Badge variant={v as "success" | "warning" | "outline"}>{g}</Badge>;
      },
      size: 64,
    },
  ];

  /* カテゴリ構成 donut --------------------------------------------- */
  const categorySegments = CATEGORY_SHARE.map((c) => ({
    label: c.category,
    value: c.sales,
    color:
      c.category === "コース"
        ? ("primary" as ChartColor)
        : c.category === "フード"
        ? ("info" as ChartColor)
        : c.category === "ドリンク"
        ? ("accent" as ChartColor)
        : ("warning" as ChartColor),
  }));
  const categoryTotal = CATEGORY_SHARE.reduce((s, c) => s + c.sales, 0);

  /* ヒートマップ ---------------------------------------------------- */
  const heatCells = HEATMAP_CELLS.map((c) => ({
    x: c.day,
    y: c.band,
    value: c.value,
    description: `${c.day}曜 ${c.band}: ${yen(c.value * 1000)}`,
  }));

  /* 客単価推移（フード/ドリンク 2系列ライン） ------------------------ */
  const perGuestSeries = [
    {
      label: "客単価",
      color: "primary" as ChartColor,
      data: PER_GUEST_TREND.map((p) => ({ label: p.weekLabel, value: p.perGuest })),
    },
    {
      label: "フード",
      color: "info" as ChartColor,
      data: PER_GUEST_TREND.map((p) => ({ label: p.weekLabel, value: p.foodPerGuest })),
    },
    {
      label: "ドリンク",
      color: "accent" as ChartColor,
      data: PER_GUEST_TREND.map((p) => ({ label: p.weekLabel, value: p.drinkPerGuest })),
    },
  ];

  return (
    <Container size="xl" as="main" className="space-y-6 px-4 py-6 sm:px-6 lg:py-8">
      {/* ── ヘッダー / 期間・店舗スイッチャー ───────────────────── */}
      <header className="flex flex-col gap-4">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="space-y-1">
            <div className="flex items-center gap-2 text-muted-foreground">
              <IconChartBar className="h-5 w-5" aria-hidden />
              <span className="text-sm font-medium">売上分析ダッシュボード</span>
            </div>
            <h1 className="text-2xl font-bold tracking-tight">
              トラットリア・アルベロ <span className="text-muted-foreground">／ {storeName}</span>
            </h1>
            <p className="text-sm text-muted-foreground">{periodMeta.rangeLabel} 時点の実績</p>
          </div>
          <Button variant="outline" size="sm" className="gap-1.5">
            <IconDownload className="h-4 w-4" aria-hidden />
            CSV出力
          </Button>
        </div>

        <div className="flex flex-wrap items-end gap-3">
          <div className="flex flex-col gap-1.5">
            <span id="period-label" className="text-xs font-medium text-muted-foreground">
              期間
            </span>
            <ToggleGroup
              type="single"
              value={period}
              disallowEmpty
              onValueChange={(v) => setPeriod(v as PeriodKey)}
              aria-labelledby="period-label"
              className="justify-start rounded-lg border border-border bg-card p-1"
            >
              {PERIODS.map((p) => (
                <ToggleGroupItem key={p.key} value={p.key} className="px-3 py-1.5 text-sm">
                  {p.label}
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </div>
          <Select
            label="店舗"
            value={storeId}
            onChange={(e) => setStoreId(e.target.value)}
            className="min-w-[180px]"
          >
            {STORES.map((s) => (
              <option key={s.id} value={s.id}>
                {s.name}
              </option>
            ))}
          </Select>
        </div>
      </header>

      <Separator />

      {/* ── 売上サマリ: ハイライト 3枚 + KPI ストリップ ─────────── */}
      <section aria-label="売上サマリ" className="space-y-4">
        <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
          <AnalyticsCard
            title={
              <span className="flex items-center gap-1.5">
                <IconReceiptYen className="h-4 w-4 text-muted-foreground" aria-hidden />
                {periodMeta.label}売上
              </span>
            }
            value={yen(kpi.netSales)}
            delta={`前年同期比 ${formatPercent(yoy / 100, { signed: true, asPercentValue: false })}`}
            deltaDescription={`前年 ${yenCompact(kpi.lastYearSales)}`}
            trend={yoy >= 0 ? "up" : "down"}
            variant={yoy >= 0 ? "positive" : "default"}
          />
          <Card className="p-0">
            <CardHeader className="space-y-1 pb-2">
              <CardTitle className="flex items-center gap-1.5 text-sm font-medium">
                <IconCoin className="h-4 w-4 text-muted-foreground" aria-hidden />
                予算達成率
              </CardTitle>
              <CardDescription>
                目標 {yenCompact(kpi.budget)} に対して {yenCompact(kpi.netSales)}
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-2">
              <div className="flex items-baseline gap-2">
                <span className="text-2xl font-bold tabular-nums tracking-tight">
                  {formatPercent(budgetRate / 100, { asPercentValue: false })}
                </span>
                <span className="text-xs text-muted-foreground">
                  残 {yen(Math.max(kpi.budget - kpi.netSales, 0))}
                </span>
              </div>
              <Meter
                value={kpi.netSales}
                max={kpi.budget}
                direction="higher-is-better"
                target={kpi.budget}
                aria-label="予算達成率"
              />
            </CardContent>
          </Card>
          <Card className="p-0">
            <CardHeader className="space-y-1 pb-2">
              <CardTitle className="flex items-center gap-1.5 text-sm font-medium">
                <IconUsers className="h-4 w-4 text-muted-foreground" aria-hidden />
                フード / ドリンク構成
              </CardTitle>
              <CardDescription>売上の内訳（{periodMeta.label}）</CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="flex items-baseline justify-between">
                <span className="text-sm">
                  フード{" "}
                  <span className="font-semibold tabular-nums">
                    {formatPercent(foodDrinkRatio, { asPercentValue: false, maximumFractionDigits: 0 })}
                  </span>
                </span>
                <span className="text-sm text-muted-foreground">
                  ドリンク{" "}
                  <span className="font-semibold tabular-nums text-foreground">
                    {formatPercent(1 - foodDrinkRatio, { asPercentValue: false, maximumFractionDigits: 0 })}
                  </span>
                </span>
              </div>
              <ChartLegend
                items={[
                  { label: "フード", value: yenCompact(kpi.foodSales), color: "info" },
                  { label: "ドリンク", value: yenCompact(kpi.drinkSales), color: "accent" },
                ]}
              />
              <Meter value={kpi.foodSales} max={kpi.foodSales + kpi.drinkSales} tone="info" aria-label="フード比率" />
            </CardContent>
          </Card>
        </div>

        <StatGroup items={stats} cols={{ base: 2, md: 4 }} />
      </section>

      {/* ── 日次売上推移 ────────────────────────────────────────── */}
      <Card className="p-0">
        <CardHeader>
          <CardTitle className="text-base">日次売上推移（当月）</CardTitle>
          <CardDescription>今年 vs 前年。点線は日商予算ライン {yen(DAILY_BUDGET_LINE)}。</CardDescription>
        </CardHeader>
        <CardContent>
          <LineChart
            series={lineSeries}
            variant="line"
            showLegend
            showGrid
            referenceValue={DAILY_BUDGET_LINE}
            referenceLabel="予算"
            formatValue={yen}
            aria-label="日次売上推移 今年と前年の比較"
          />
        </CardContent>
      </Card>

      {/* ── 時間帯別 + カテゴリ構成 ─────────────────────────────── */}
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
        <Card className="p-0">
          <CardHeader>
            <CardTitle className="text-base">時間帯別売上</CardTitle>
            <CardDescription>ランチ / アイドル / ディナー（フード・ドリンク内訳）</CardDescription>
          </CardHeader>
          <CardContent>
            <StackedBarChart
              data={daypartGroups}
              variant="vertical"
              showLegend
              showValues
              formatValue={yenCompact}
              aria-label="時間帯別売上 フードとドリンクの内訳"
            />
          </CardContent>
        </Card>

        <LabeledDonutCard
          title="カテゴリ構成"
          description="売上比率（当月）"
          segments={categorySegments}
          centerLabel="合計"
          centerValue={yenCompact(categoryTotal)}
          totalLabel="売上"
          formatValue={yen}
          showCallouts
          className="p-0"
        />
      </div>

      {/* ── メニュー別 ABC / パレート ───────────────────────────── */}
      <Card className="p-0">
        <CardHeader>
          <CardTitle className="flex flex-wrap items-center gap-2 text-base">
            メニュー別 ABC分析
            <Badge variant="success">A</Badge>
            <span className="text-xs font-normal text-muted-foreground">累積70%まで</span>
            <Badge variant="warning">B</Badge>
            <span className="text-xs font-normal text-muted-foreground">〜90%</span>
            <Badge variant="outline">C</Badge>
          </CardTitle>
          <CardDescription className="flex items-center gap-1.5">
            <IconInfoCircle className="h-3.5 w-3.5" aria-hidden />
            売上の80%を生む主力メニューを把握（パレートの法則）
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-6">
          <ParetoChart
            data={paretoData}
            sort
            threshold={80}
            thresholdLabel="80%ライン"
            formatValue={yenCompact}
            showValues={false}
            label="売上"
            cumulativeLabel="累積構成比"
            aria-label="メニュー別売上のパレート図 累積構成比つき"
          />
          <DataTable
            columns={columns}
            data={ranked}
            aria-label="メニュー別ランキング表"
          />
        </CardContent>
      </Card>

      {/* ── 曜日×時間帯 ヒートマップ + 客単価推移 ─────────────────── */}
      <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
        <Card className="p-0">
          <CardHeader>
            <CardTitle className="text-base">曜日 × 時間帯 ヒートマップ</CardTitle>
            <CardDescription>売上が強い日・時間帯（千円）。金土ディナーが最需要。</CardDescription>
          </CardHeader>
          <CardContent>
            <HeatmapChart
              data={heatCells}
              xLabels={HEATMAP_DAYS}
              yLabels={HEATMAP_BANDS}
              color="primary"
              showValues
              formatValue={sen}
              aria-label="曜日と時間帯ごとの売上ヒートマップ"
            />
          </CardContent>
        </Card>

        <Card className="p-0">
          <CardHeader>
            <CardTitle className="text-base">客単価の推移</CardTitle>
            <CardDescription>週次。フード／ドリンクの内訳つき。</CardDescription>
          </CardHeader>
          <CardContent>
            <LineChart
              series={perGuestSeries}
              variant="line"
              showLegend
              showGrid
              showDots
              formatValue={yen}
              aria-label="客単価の週次推移 フードとドリンクの内訳"
            />
          </CardContent>
        </Card>
      </div>

      <footer className="flex items-center gap-2 pt-2 text-xs text-muted-foreground">
        <IconBuildingStore className="h-3.5 w-3.5" aria-hidden />
        データは {periodMeta.rangeLabel} 時点。POS連携・税抜・サービス料除く。
      </footer>
    </Container>
  );
}

/**
 * 飲食店 売上分析ダッシュボードのモックデータ。
 * 店舗: トラットリア・アルベロ（銀座本店）など。客単価・客数・原価率は
 * 実際のディナー中心イタリアンの値を想定（客単価 ¥6,000〜7,500 帯）。
 *
 * すべて純データ（関数を含まない）なので Server / Client どちらからも import 可。
 */

export type PeriodKey = "day" | "week" | "month";

export const PERIODS: { key: PeriodKey; label: string; rangeLabel: string }[] = [
  { key: "day", label: "当日", rangeLabel: "2026年6月26日（金）" },
  { key: "week", label: "今週", rangeLabel: "6月22日〜6月28日" },
  { key: "month", label: "当月", rangeLabel: "2026年6月（1日〜26日）" },
];

export const STORES = [
  { id: "ginza", name: "銀座本店" },
  { id: "shibuya", name: "渋谷スクランブル店" },
  { id: "yokohama", name: "横浜みなとみらい店" },
] as const;

/** KPI サマリ（期間ごとに値を差し替え） */
export interface KpiSummary {
  /** 売上（円） */
  netSales: number;
  /** 前年同期売上（円） */
  lastYearSales: number;
  /** 予算（円） */
  budget: number;
  /** 客数（人） */
  guests: number;
  /** 組数 */
  groups: number;
  /** 客単価（円） */
  perGuest: number;
  /** 回転率（席あたり） */
  turnover: number;
  /** 原価率（0-1） */
  costRatio: number;
  /** フード売上比率 / ドリンク売上比率 */
  foodSales: number;
  drinkSales: number;
}

export const KPI_BY_PERIOD: Record<PeriodKey, KpiSummary> = {
  day: {
    netSales: 642_800,
    lastYearSales: 588_200,
    budget: 620_000,
    guests: 94,
    groups: 38,
    perGuest: 6_838,
    turnover: 2.6,
    costRatio: 0.312,
    foodSales: 418_200,
    drinkSales: 224_600,
  },
  week: {
    netSales: 4_186_500,
    lastYearSales: 3_902_000,
    budget: 4_350_000,
    guests: 612,
    groups: 248,
    perGuest: 6_841,
    turnover: 2.4,
    costRatio: 0.298,
    foodSales: 2_742_000,
    drinkSales: 1_444_500,
  },
  month: {
    netSales: 16_842_300,
    lastYearSales: 15_120_400,
    budget: 17_500_000,
    guests: 2_486,
    groups: 1_004,
    perGuest: 6_775,
    turnover: 2.3,
    costRatio: 0.305,
    foodSales: 10_980_000,
    drinkSales: 5_862_300,
  },
};

/** 日次売上推移（当月 1〜26日）— 当年実績 vs 前年 vs 予算ライン */
export interface DailyPoint {
  day: number;
  sales: number;
  lastYear: number;
}

/** 予算は日商の目標ライン（¥17,500,000 / 30日 ≒ ¥583,000） */
export const DAILY_BUDGET_LINE = 583_000;

export const DAILY_SALES: DailyPoint[] = [
  { day: 1, sales: 524_000, lastYear: 498_000 },
  { day: 2, sales: 612_000, lastYear: 540_000 },
  { day: 3, sales: 588_000, lastYear: 561_000 },
  { day: 4, sales: 498_000, lastYear: 472_000 },
  { day: 5, sales: 702_000, lastYear: 631_000 }, // 金
  { day: 6, sales: 812_000, lastYear: 744_000 }, // 土
  { day: 7, sales: 596_000, lastYear: 552_000 }, // 日
  { day: 8, sales: 412_000, lastYear: 438_000 }, // 月・雨
  { day: 9, sales: 532_000, lastYear: 501_000 },
  { day: 10, sales: 604_000, lastYear: 566_000 },
